import { CallStatus, ApiResponse, PaginatedResult } from "@/types/api.types";
import { StateData } from "@/store/types";
import { Dispatch, SetStateAction } from "react";
import { ExtractCorrelationId } from "@/utils/common";
import { mapHttpStatusToCallStatus } from "@/utils/httpStatus";

const setInitialState = <T,>(setState: (state: StateData<T>) => void) => {
    setState({
        data: {} as T,
        status: CallStatus.InProgress,
        httpStatus: 0,
        timestamp: new Date(),
    });
};

const setSuccessState = <T,>(setState: (state: StateData<T>) => void, response: { data: ApiResponse<T> }) => {
    setState({
        data: (response.data.result ?? ({} as T)),
        status: CallStatus.Success,
        httpStatus: response.data.status,
        timestamp: new Date(),
        correlationId: ExtractCorrelationId(response),
    });
};

const setFailureState = <T,>(setState: (state: StateData<T>) => void, error: any) => {
    const httpStatus = error.response ? error.response.status : 0;
    setState({
        data: {} as T,
        status: mapHttpStatusToCallStatus(httpStatus),
        httpStatus: httpStatus,
        timestamp: new Date(),
        correlationId: ExtractCorrelationId(error),
    });
};

export const ApiGlobalStateManager = async <T,>(apiRequest: Promise<{ data: ApiResponse<T> }>, setGlobalState: (state: StateData<T>) => void) => {
    setInitialState(setGlobalState);

    try {
        const response = await apiRequest;
        setSuccessState(setGlobalState, response);
    } catch (error) {
        setFailureState(setGlobalState, error);
    }
};

// Specialized version for paginated results that extracts items for global state
export const ApiGlobalStateManagerPaginated = async <T,>(apiRequest: Promise<{ data: ApiResponse<PaginatedResult<T>> }>, setGlobalState: (state: StateData<T[]>) => void) => {
    setInitialState(setGlobalState);

    try {
        const response = await apiRequest;
        // Extract items from paginated result for global state compatibility
        const paginatedResult = response.data.result;
        const items = paginatedResult?.items || [];

        // Reuse the original axios response so headers (correlation id) flow through.
        const itemsResponse = {
            ...response,
            data: {
                status: response.data.status,
                errorCode: response.data.errorCode,
                result: items,
            } satisfies ApiResponse<T[]>,
        };

        setSuccessState(setGlobalState, itemsResponse);
    } catch (error) {
        setFailureState(setGlobalState, error);
    }
};

export const ApiComponentStateManager = async <T,>(apiRequest: Promise<{ data: ApiResponse<T> }>, setComponentState: Dispatch<SetStateAction<StateData<T>>>) => {
    setInitialState(setComponentState);

    try {
        const response = await apiRequest;
        if (response.data.status >= 200 && response.data.status < 300) {
            setSuccessState(setComponentState, response);
        } else {
            let status = mapHttpStatusToCallStatus(response.data.status);
            
            setComponentState({
                data: {} as T,
                status: status,
                httpStatus: response.data.status,
                timestamp: new Date(),
                correlationId: ExtractCorrelationId(response),
            });
        }
    } catch (error) {
        setFailureState(setComponentState, error);
    }
};

